const t=[{title:"1. Nền tảng câu",topics:[{id:"c1-1",title:"Cấu trúc S-V-O & Động từ To-be",description:"Hiểu cấu trúc cốt lõi và khắc phục lỗi quên 'to be' ('Tôi mệt' vs 'I am tired').",progress:100,isLocked:!1,icon:"🏗️"},{id:"c1-2",title:"Danh từ số ít/số nhiều (-s/-es)",description:"Nắm vững quy tắc số lượng để tránh lỗi thiếu 's' cực kỳ phổ biến.",progress:30,isLocked:!1,icon:"🍎"},{id:"c1-3",title:"Mạo từ cơ bản (a/an/the)",description:"Hiểu rõ khi nào dùng a, an, the để câu chuẩn xác hơn.",progress:0,isLocked:!1,icon:"🏷️"}]},{title:"2. Thì cơ bản (Ưu tiên tần suất)",topics:[{id:"c2-1",title:"Hiện Tại Đơn",description:"Diễn đạt thói quen, sự thật — thì được sử dụng nhiều nhất.",progress:0,isLocked:!0,icon:"🌞"},{id:"c2-2",title:"Hiện Tại Tiếp Diễn",description:"Nói về việc đang xảy ra ngay lúc này.",progress:0,isLocked:!0,icon:"🏃"},{id:"c2-3",title:"Quá Khứ Đơn",description:"Kể chuyện, tường thuật những gì đã qua.",progress:0,isLocked:!0,icon:"⏪"},{id:"c2-4",title:"Tương Lai Gần (going to/will)",description:"Diễn đạt dự định, kế hoạch cho tương lai.",progress:0,isLocked:!0,icon:"🔮"}]},{title:"3. Từ nối câu cơ bản",topics:[{id:"c3-1",title:"Đại từ nhân xưng & Sở hữu",description:"Nền tảng bắt buộc trước khi ghép câu phức (I/my, you/your...).",progress:0,isLocked:!0,icon:"👤"},{id:"c3-2",title:"Giới từ chỉ Thời gian/Nơi chốn",description:"Luyện tập in/on/at để không bị lẫn lộn.",progress:0,isLocked:!0,icon:"📍"},{id:"c3-3",title:"Liên từ cơ bản (and/but/so/because)",description:"Ghép ý để thoát khỏi câu đơn rời rạc.",progress:0,isLocked:!0,icon:"🔗"}]},{title:"4. Câu hỏi & Phủ định",topics:[{id:"c4-1",title:"Câu hỏi Yes/No & Wh-",description:"Làm quen với cấu trúc đảo ngữ (do/does/did) hoàn toàn xa lạ với tiếng Việt.",progress:0,isLocked:!0,icon:"❓"},{id:"c4-2",title:"Câu Phủ định",description:"Cách dùng don't/doesn't/didn't một cách chính xác.",progress:0,isLocked:!0,icon:"❌"}]},{title:"5. So sánh & Tính từ",topics:[{id:"c5-1",title:"Trật tự tính từ",description:"Đặt tính từ trước danh từ thay vì phía sau như tiếng Việt.",progress:0,isLocked:!0,icon:"🎨"},{id:"c5-2",title:"So sánh Hơn & Nhất",description:"Cấu trúc dễ luyện tập qua ví dụ thực tế.",progress:0,isLocked:!0,icon:"📏"}]}],i={"c1-1":{discovery:[{en:"I am happy.",vi:"Tôi vui.",highlight:"am"},{en:"She is a doctor.",vi:"Cô ấy là bác sĩ.",highlight:"is"},{en:"They are students.",vi:"Họ là học sinh.",highlight:"are"}],guidedQuestion:{question:"Bạn thấy điểm khác biệt lớn nhất giữa câu 'I am tired' và 'Tôi mệt' là gì?",options:[{id:1,text:"Tiếng Anh luôn cần động từ 'tobe' (am/is/are) trước tính từ, còn tiếng Việt thì không cần chữ 'là'."},{id:2,text:"Tiếng Anh dùng sai từ vựng, đáng lẽ phải là 'I tired'."}],correctId:1},rule:{title:"Trong tiếng Anh, TẤT CẢ các câu đều phải có Động từ.",description:"Nếu câu không có động từ hành động (như chạy, nhảy, ăn), bạn bắt buộc phải dùng động từ To-be (am/is/are)."},trueFalse:{sentence:"I am a student.",translation:"Tôi là một học sinh.",isActuallyCorrect:!0},fixError:{incorrect:"I tired.",correct:"I am tired."},freeOutput:{prompt:"Hãy viết 1 câu tiếng Anh miêu tả cảm xúc hiện tại của bạn (có sử dụng to-be)."}},"c1-2":{discovery:[{en:"I have one apple.",vi:"Tôi có một quả táo.",highlight:"apple"},{en:"I have two apples.",vi:"Tôi có hai quả táo.",highlight:"apples"},{en:"She has three cats.",vi:"Cô ấy có ba con mèo.",highlight:"cats"}],guidedQuestion:{question:"Khi nói về số lượng từ 2 trở lên, từ trong tiếng Anh thay đổi thế nào so với tiếng Việt?",options:[{id:1,text:"Tiếng Anh phải thêm 's' hoặc 'es' vào cuối danh từ, còn tiếng Việt chỉ cần thêm số từ đằng trước."},{id:2,text:"Cả tiếng Anh và tiếng Việt đều không thay đổi danh từ."}],correctId:1},rule:{title:"Danh từ đếm được số nhiều luôn có đuôi -s hoặc -es.",description:"Khác với tiếng Việt (chỉ thêm 'những/các' hoặc số đếm), tiếng Anh bắt buộc phải biến đổi hình thái của danh từ."},trueFalse:{sentence:"I have two dog.",translation:"Tôi có hai con chó.",isActuallyCorrect:!1},fixError:{incorrect:"I have three book",correct:"I have three books"},freeOutput:{prompt:"Viết 1 câu tiếng Anh kể về số lượng đồ vật bạn đang có trên bàn (ví dụ: I have two pens)."}},"c1-3":{discovery:[{en:"I have a cat.",vi:"Tôi có một con mèo.",highlight:"a"},{en:"The cat is black.",vi:"Con mèo đó màu đen.",highlight:"The"},{en:"I eat an apple.",vi:"Tôi ăn một quả táo.",highlight:"an"}],guidedQuestion:{question:"Sự khác biệt khi dùng 'a/an' và 'the' là gì?",options:[{id:1,text:"'a/an' dùng cho vật nhắc đến lần đầu, chưa xác định; 'the' dùng cho vật đã xác định."},{id:2,text:"'a/an' dùng cho số nhiều, 'the' dùng cho số ít."}],correctId:1},rule:{title:"Mạo từ a/an và the",description:"Dùng 'a' hoặc 'an' (trước nguyên âm u,e,o,a,i) khi nhắc tới một vật lần đầu tiên. Dùng 'the' khi cả người nói và người nghe đều biết đang nói về vật nào."},trueFalse:{sentence:"I saw a dog. A dog was very big.",translation:"Tôi thấy một con chó. Con chó đó rất to.",isActuallyCorrect:!1},fixError:{incorrect:"I have an car.",correct:"I have a car."},freeOutput:{prompt:"Hãy viết 2 câu mô tả một món đồ bạn mới mua (Dùng 'a' ở câu đầu và 'the' ở câu sau)."}},"c2-1":{discovery:[{en:"I wake up at 7 AM.",vi:"Tôi thức dậy lúc 7 giờ sáng.",highlight:"wake up"},{en:"He goes to school.",vi:"Anh ấy đi học.",highlight:"goes"},{en:"The sun rises in the east.",vi:"Mặt trời mọc ở hướng đông.",highlight:"rises"}],guidedQuestion:{question:"Khi nào chúng ta sử dụng thì Hiện Tại Đơn?",options:[{id:1,text:"Để nói về thói quen, lịch trình và sự thật hiển nhiên."},{id:2,text:"Để nói về những việc đang xảy ra ngay lúc này."}],correctId:1},rule:{title:"Hiện Tại Đơn (Present Simple)",description:"Dùng để diễn tả thói quen lặp đi lặp lại hoặc sự thật hiển nhiên. Lưu ý thêm 's' hoặc 'es' vào động từ nếu chủ ngữ là ngôi thứ 3 số ít (He/She/It)."},trueFalse:{sentence:"She play tennis every weekend.",translation:"Cô ấy chơi tennis mỗi cuối tuần.",isActuallyCorrect:!1},fixError:{incorrect:"He walk to school everyday.",correct:"He walks to school everyday."},freeOutput:{prompt:"Hãy viết 1 câu mô tả một việc bạn thường xuyên làm vào buổi sáng."}},"c2-2":{discovery:[{en:"I am reading a book.",vi:"Tôi đang đọc sách.",highlight:"am reading"},{en:"They are playing football.",vi:"Họ đang chơi bóng đá.",highlight:"are playing"},{en:"She is working now.",vi:"Cô ấy đang làm việc bây giờ.",highlight:"is working"}],guidedQuestion:{question:"Thì Hiện Tại Tiếp Diễn được cấu tạo như thế nào?",options:[{id:1,text:"Chỉ cần thêm đuôi -ing vào động từ chính."},{id:2,text:"Động từ to-be (am/is/are) kết hợp với động từ thêm đuôi -ing (V-ing)."}],correctId:2},rule:{title:"Hiện Tại Tiếp Diễn (Present Continuous)",description:"Dùng để diễn tả hành động đang diễn ra ngay tại thời điểm nói. Cấu trúc bắt buộc: Tobe (am/is/are) + V-ing."},trueFalse:{sentence:"I am eat my lunch now.",translation:"Tôi đang ăn bữa trưa của tôi bây giờ.",isActuallyCorrect:!1},fixError:{incorrect:"She watching TV right now.",correct:"She is watching TV right now."},freeOutput:{prompt:"Viết 1 câu tiếng Anh mô tả một việc bạn ĐANG LÀM ngay lúc này."}},"c2-3":{discovery:[{en:"I watched a movie yesterday.",vi:"Tôi đã xem một bộ phim hôm qua.",highlight:"watched"},{en:"She went to Paris last year.",vi:"Cô ấy đã đi Paris năm ngoái.",highlight:"went"},{en:"We played tennis last weekend.",vi:"Chúng tôi đã chơi tennis cuối tuần trước.",highlight:"played"}],guidedQuestion:{question:"Dấu hiệu nhận biết thì Quá Khứ Đơn trong các ví dụ trên là gì?",options:[{id:1,text:"Động từ thêm '-ed' hoặc chuyển thành dạng bất quy tắc (như 'went')."},{id:2,text:"Động từ giữ nguyên và có thêm từ 'last' ở đầu câu."}],correctId:1},rule:{title:"Quá Khứ Đơn (Past Simple)",description:"Dùng để diễn tả hành động đã xảy ra và chấm dứt trong quá khứ. Động từ có thể theo quy tắc (thêm -ed) hoặc bất quy tắc (như go -> went)."},trueFalse:{sentence:"I buy a new shirt yesterday.",translation:"Tôi đã mua một chiếc áo mới hôm qua.",isActuallyCorrect:!1},fixError:{incorrect:"I seed him last night.",correct:"I saw him last night."},freeOutput:{prompt:"Hãy viết 1 câu kể về một việc bạn ĐÃ LÀM vào hôm qua."}},"c2-4":{discovery:[{en:"I will call you tomorrow.",vi:"Tôi sẽ gọi bạn ngày mai.",highlight:"will call"},{en:"She is going to visit her mom.",vi:"Cô ấy dự định sẽ đi thăm mẹ.",highlight:"is going to visit"}],guidedQuestion:{question:"Sự khác biệt cơ bản giữa 'will' và 'be going to' là gì?",options:[{id:1,text:"'will' dùng cho quyết định tức thời, 'be going to' dùng cho kế hoạch đã dự định trước."},{id:2,text:"'will' dùng trong quá khứ, 'be going to' dùng trong tương lai."}],correctId:1},rule:{title:"Tương lai (will / be going to)",description:"Dùng để diễn đạt hành động trong tương lai. 'Will' dùng khi bạn vừa mới quyết định lúc nói, 'be going to' dùng khi đã lên kế hoạch từ trước."},trueFalse:{sentence:"Look at the dark clouds! It will rain.",translation:"Nhìn những đám mây đen kìa! Trời sẽ mưa.",isActuallyCorrect:!1},fixError:{incorrect:"I am going call you back.",correct:"I will call you back. (Hoặc I am going to call you back)."},freeOutput:{prompt:"Viết 1 câu tiếng Anh về một việc bạn ĐÃ CÓ KẾ HOẠCH làm vào cuối tuần này."}},"c3-1":{discovery:[{en:"She is my friend.",vi:"Cô ấy là bạn của tôi.",highlight:"She, my"},{en:"He drove his car.",vi:"Anh ấy đã lái xe của anh ấy.",highlight:"He, his"},{en:"They like their house.",vi:"Họ thích ngôi nhà của họ.",highlight:"They, their"}],guidedQuestion:{question:"Trong câu 'He drove his car', từ nào đóng vai trò Chủ ngữ và từ nào mang tính Sở hữu?",options:[{id:1,text:"Chủ ngữ là 'He', Sở hữu là 'his'."},{id:2,text:"Chủ ngữ là 'his', Sở hữu là 'car'."}],correctId:1},rule:{title:"Đại từ nhân xưng & Sở hữu",description:"Tiếng Anh phân biệt rõ ràng từ dùng để chỉ người làm chủ hành động (I, You, We, They, He, She, It) và từ chỉ sự sở hữu (my, your, our, their, his, her, its)."},trueFalse:{sentence:"Me have a new phone.",translation:"Tôi có một chiếc điện thoại mới.",isActuallyCorrect:!1},fixError:{incorrect:"She loves she cat.",correct:"She loves her cat."},freeOutput:{prompt:"Hãy viết 1 câu giới thiệu một người bạn của bạn (Dùng đại từ nhân xưng và sở hữu, ví dụ: He is Tom, his hair is black)."}},"c3-2":{discovery:[{en:"I wake up at 7 AM.",vi:"Tôi thức dậy lúc 7 giờ sáng.",highlight:"at"},{en:"My birthday is in June.",vi:"Sinh nhật tôi vào tháng 6.",highlight:"in"},{en:"I will see you on Monday.",vi:"Tôi sẽ gặp bạn vào thứ Hai.",highlight:"on"}],guidedQuestion:{question:"Theo các ví dụ trên, quy tắc cơ bản của giới từ thời gian là gì?",options:[{id:1,text:"'at' đi với giờ, 'in' đi với tháng/năm, 'on' đi với ngày."},{id:2,text:"'at' đi với ngày, 'in' đi với giờ, 'on' đi với tháng."}],correctId:1},rule:{title:"Giới từ Thời gian & Nơi chốn (IN/ON/AT)",description:"Quy tắc chóp ngược: IN (Rộng: tháng, năm, quốc gia), ON (Cụ thể hơn: ngày trong tuần, trên đường), AT (Rất cụ thể: giờ chính xác, địa chỉ cụ thể)."},trueFalse:{sentence:"I was born on 1990.",translation:"Tôi sinh vào năm 1990.",isActuallyCorrect:!1},fixError:{incorrect:"Let's meet in 8 PM.",correct:"Let's meet at 8 PM."},freeOutput:{prompt:"Viết 1 câu nói về thời gian (giờ hoặc ngày) bạn thường đi ngủ (Dùng giới từ)."}},"c3-3":{discovery:[{en:"I like tea and coffee.",vi:"Tôi thích trà và cà phê.",highlight:"and"},{en:"He is rich but unhappy.",vi:"Anh ấy giàu nhưng không hạnh phúc.",highlight:"but"},{en:"It rained, so I stayed home.",vi:"Trời mưa, vì vậy tôi ở nhà.",highlight:"so"}],guidedQuestion:{question:"Liên từ 'so' và 'because' có gì khác nhau?",options:[{id:1,text:"'so' chỉ kết quả (vì vậy), 'because' chỉ nguyên nhân (bởi vì)."},{id:2,text:"'so' dùng ở đầu câu, 'because' dùng ở cuối câu."}],correctId:1},rule:{title:"Liên từ cơ bản (And/But/So/Because)",description:"Dùng để nối các ý lại với nhau, giúp câu văn dài và tự nhiên hơn. 'And' (và), 'But' (nhưng), 'So' (vì vậy), 'Because' (bởi vì)."},trueFalse:{sentence:"I didn't go to school so I was sick.",translation:"Tôi đã không đến trường vì vậy tôi ốm.",isActuallyCorrect:!1},fixError:{incorrect:"I am tired because I will go to sleep.",correct:"I am tired so I will go to sleep."},freeOutput:{prompt:"Viết 1 câu dài giải thích lý do tại sao bạn thích học tiếng Anh (Dùng because hoặc so)."}},"c4-1":{discovery:[{en:"Do you like pizza?",vi:"Bạn có thích pizza không?",highlight:"Do you"},{en:"Does he work here?",vi:"Anh ấy có làm việc ở đây không?",highlight:"Does he"},{en:"Where do you live?",vi:"Bạn sống ở đâu?",highlight:"Where do"}],guidedQuestion:{question:"Để đặt câu hỏi cho động từ thường (không phải to-be) trong tiếng Anh, ta phải làm gì?",options:[{id:1,text:"Chỉ cần lên giọng ở cuối câu là thành câu hỏi."},{id:2,text:"Phải mượn trợ động từ (do/does/did) đặt lên trước chủ ngữ."}],correctId:2},rule:{title:"Câu hỏi Yes/No & Câu hỏi có từ để hỏi (Wh-)",description:"Khác với tiếng Việt chỉ thêm từ 'không?' vào cuối câu, tiếng Anh bắt buộc phải đảo trợ động từ (Do/Does/Did) lên trước chủ ngữ. Từ để hỏi (Where/What/Who...) sẽ đứng trước trợ động từ."},trueFalse:{sentence:"You like pizza?",translation:"Bạn thích pizza không?",isActuallyCorrect:!1},fixError:{incorrect:"What you do every morning?",correct:"What do you do every morning?"},freeOutput:{prompt:"Hãy đặt 1 câu hỏi (bằng tiếng Anh) để hỏi xem bạn của bạn sống ở đâu."}},"c4-2":{discovery:[{en:"I do not (don't) eat meat.",vi:"Tôi không ăn thịt.",highlight:"don't"},{en:"She does not (doesn't) like him.",vi:"Cô ấy không thích anh ta.",highlight:"doesn't"},{en:"They did not (didn't) go.",vi:"Họ đã không đi.",highlight:"didn't"}],guidedQuestion:{question:"Để nói 'không' với động từ thường, tiếng Anh dùng cấu trúc gì?",options:[{id:1,text:"Thêm từ 'not' ngay trước động từ chính (I not eat)."},{id:2,text:"Dùng trợ động từ + not (don't/doesn't/didn't) đặt trước động từ chính."}],correctId:2},rule:{title:"Câu Phủ định",description:"Trong tiếng Anh, không thể đơn giản thêm từ 'not' (không). Bạn phải mượn trợ động từ: don't/doesn't (hiện tại), didn't (quá khứ)."},trueFalse:{sentence:"He don't know the answer.",translation:"Anh ấy không biết câu trả lời.",isActuallyCorrect:!1},fixError:{incorrect:"I not like this movie.",correct:"I don't like this movie."},freeOutput:{prompt:"Viết 1 câu phủ định về một việc bạn KHÔNG làm vào ngày hôm qua."}},"c5-1":{discovery:[{en:"A beautiful house.",vi:"Một ngôi nhà đẹp.",highlight:"beautiful house"},{en:"A red car.",vi:"Một chiếc xe màu đỏ.",highlight:"red car"}],guidedQuestion:{question:"Vị trí của tính từ trong tiếng Anh so với tiếng Việt có gì khác nhau?",options:[{id:1,text:"Tiếng Anh đặt tính từ (đẹp, đỏ) TRƯỚC danh từ, ngược lại với tiếng Việt."},{id:2,text:"Giống y hệt tiếng Việt."}],correctId:1},rule:{title:"Trật tự tính từ cơ bản",description:"Trong cụm danh từ tiếng Anh, tính từ mô tả đặc điểm LUÔN ĐỨNG TRƯỚC danh từ chính. (Ví dụ: Một cô gái đẹp = A beautiful girl, không phải A girl beautiful)."},trueFalse:{sentence:"I have a car black.",translation:"Tôi có một chiếc xe màu đen.",isActuallyCorrect:!1},fixError:{incorrect:"She is a girl very smart.",correct:"She is a very smart girl."},freeOutput:{prompt:"Viết cụm từ tiếng Anh: Một chiếc áo sơ mi mới."}},"c5-2":{discovery:[{en:"She is taller than me.",vi:"Cô ấy cao hơn tôi.",highlight:"taller than"},{en:"He is the smartest student.",vi:"Anh ấy là học sinh thông minh nhất.",highlight:"the smartest"},{en:"This book is more interesting.",vi:"Cuốn sách này thú vị hơn.",highlight:"more interesting"}],guidedQuestion:{question:"Khi nào ta dùng đuôi '-er' và khi nào dùng 'more' trong so sánh hơn?",options:[{id:1,text:"Dùng '-er' cho từ ngắn (1 âm tiết), dùng 'more' cho từ dài (từ 2 âm tiết trở lên)."},{id:2,text:"Dùng từ nào cũng được, không quan trọng độ dài của từ."}],correctId:1},rule:{title:"So sánh Hơn & So sánh Nhất",description:"Tính từ ngắn: thêm -er (so sánh hơn), the + -est (so sánh nhất). Tính từ dài: thêm more (so sánh hơn), the most (so sánh nhất). Lưu ý luôn có 'than' ở so sánh hơn."},trueFalse:{sentence:"My house is more big than your house.",translation:"Nhà tôi to hơn nhà bạn.",isActuallyCorrect:!1},fixError:{incorrect:"He is the most tall boy in class.",correct:"He is the tallest boy in class."},freeOutput:{prompt:"Viết 1 câu so sánh chiều cao của bạn với một người bạn khác."}}};export{i as B,t as G};
